import json, os
def test_trade_count_no_regression(baseline_trades=None):
    data_dir = 'hermes_v6/data/sandbox_trading_intraday_500_v316'
    audit_path = os.path.join(data_dir, 'audit.log')
    count = 0
    with open(audit_path) as f:
        for line in f:
            try:
                evt = json.loads(line)
                if evt.get('action') in ('open', 'close'):
                    count += 1
            except json.JSONDecodeError:
                continue
    if baseline_trades is None:
        print(f'⚠ 无基线, 当前交易笔数: {count}')
        return
    drop = (baseline_trades - count) / baseline_trades if baseline_trades else 0
    assert drop < 0.30, f'交易笔数下降 {drop:.1%} > 30%, 触发回滚'
    print(f'✓ 交易笔数无骤降 (下降 {drop:.1%})')

